  live_view_links = bb.sessions.debug(session.id)
  all_tabs = live_view_links.pages
  second_tab_live_view_link = all_tabs[1].debuggerFullscreenUrl
  print(f"Second Tab Live View Link: {second_tab_live_view_link}")
