        );

        console.log("Taking a screenshot!");
        await page.screenshot({ fullPage: true });

        console.log("Shutting down...");
        await page.close();
        await browser.close();

        console.log(
          `Session complete! View recording at https://browserbase.com/sessions/${session.id}`,
        );
      })();
